package main

// The problem requires finding the maximum binary number formed by concatenating segments,
// where each segment is of the form 1...10...0, and returning the result modulo 10^9 + 7.
// The maximum is achieved by sorting the segments lexicographically: segment A comes before segment B
// if A+B > B+A lexicographically.

import (
	"math/big"
	"sort"
)

// Segment structure to hold the components of each segment
type Segment struct {
	Nums1 int64
	Nums0 int64
}

func solve(nums1 []int64, nums0 []int64) int64 {
	const MOD int64 = 1000000007

	n := len(nums1)
	segments := make([]Segment, n)

	// 1. Construct the segments
	for i := 0; i < n; i++ {
		segments[i] = Segment{Nums1: nums1[i], Nums0: nums0[i]}
	}

	// 2. Custom sorting based on lexicographical comparison: A+B vs B+A
	sort.Slice(segments, func(i, j int) bool {
		segA := segments[i]
		segB := segments[j]

		// Segment A: 1^a 0^b
		// Segment B: 1^c 0^d

		// We need to compare (1^a 0^b)(1^c 0^d) vs (1^c 0^d)(1^a 0^b)

		// Construct the concatenated strings explicitly for comparison,
		// as direct arithmetic comparison is complex due to the mixed 1s and 0s structure.
		// Given the constraints (total length <= 2*10^5), string construction and comparison is feasible.

		// Helper function to build the string representation of a segment
		buildSegmentStr := func(s Segment) string {
			ones := make([]byte, s.Nums1)
			zeros := make([]byte, s.Nums0)
			for k := range ones {
				ones[k] = '1'
			}
			for k := range zeros {
				zeros[k] = '0'
			}
			return string(ones) + string(zeros)
		}

		strA := buildSegmentStr(segA)
		strB := buildSegmentStr(segB)

		// Compare strA + strB vs strB + strA lexicographically.
		// We return true if strA should come before strB (i.e., A+B > B+A).
		orderAB := strA + strB
		orderBA := strB + strA

		return orderAB > orderBA
	})

	// 3. Concatenate the sorted segments and calculate the result modulo MOD
	finalString := ""
	for _, seg := range segments {
		// Rebuild segment string for concatenation
		ones := make([]byte, seg.Nums1)
		zeros := make([]byte, seg.Nums0)
		for k := range ones {
			ones[k] = '1'
		}
		for k := range zeros {
			zeros[k] = '0'
		}
		finalString += string(ones) + string(zeros)
	}

	// Calculate the value of the binary string modulo MOD
	var finalResult int64 = 0

	// Iterative calculation: result = (result * 2 + digit) % MOD
	for _, char := range finalString {
		digit := int64(0)
		if char == '1' {
			digit = 1
		}

		// result = (result * 2) % MOD
		finalResult = (finalResult * 2) % MOD

		// result = (result + digit) % MOD
		finalResult = (finalResult + digit) % MOD
	}

	return finalResult
}
